mapper.select:
SELECT a.id, a.merchant_id as merchantId, m.merchant_name as merchantName, m.logo, m.merchant_type as merchantType, m.business_license as businessLicense, m.unified_social_credit_code as unifiedSocialCreditCode, m.legal_person as legalPerson, m.business_scope as businessScope, m.background_image as backgroundImage, u.name as applicantName, u.phone as applicantPhone, a.status, a.create_time as createTime, a.review_time as reviewTime, a.review_comment as reviewComment, asoc.alumni_association_id as asoc_id, asoc.association_name as asoc_name, asoc.logo as asoc_logo FROM merchant_alumni_association_apply a JOIN merchant m ON a.merchant_id = m.merchant_id JOIN wx_user_info u ON a.applicant_wx_id = u.wx_id LEFT JOIN alumni_association asoc ON a.alumni_association_id = asoc.alumni_association_id WHERE a.status != 3 AND a.is_delete = 0 AND m.is_delete = 0 AND u.is_delete = 0
AND a.alumni_association_id = #{alumniAssociationId}
AND a.merchant_id = #{merchantId}
AND a.status = #{status}
ORDER BY a.create_time DESC
